/**
 * Wiki version-history screenshot seed (wiki-vc-screenshots sub-bot of HR,
 * 2026-05-31).
 *
 * `?wikiCapture=1` is a READ-ONLY fixture: there is no live editing, so the
 * multi-version Notes history the wiki version-history page screenshots needs
 * cannot be generated by typing. This module pre-seeds a VALID, real-engine-
 * produced history for note id 5 (alex's "qPCR optimization log") into the
 * fixture's in-memory `_history` text store, plus a fresh 24h `revert_undo_window`
 * on the live note so the "Undo restore" header affordance renders.
 *
 * How the jsonl was made (NOT hand-faked): a throwaway vitest generator ran the
 * ACTUAL `HistoryEngine.appendEdit` (src/lib/history/__generate-wiki-history.
 * test.ts) against an in-memory store with an injected clock + two actors (alex,
 * morgan), then dumped the produced jsonl. So every row is a real GenesisRow /
 * DeltaRow with a correct jsdiff delta + sha256 post_hash. The 9 rows are:
 *   genesis, create(entry1), add(entry2)  [alex],
 *   edit entry1 numbers, add(entry3 draft) [morgan],
 *   tighten description, finalize entry3   [alex],
 *   revert -> draft state, undo-revert -> HEAD [alex].
 *
 * Timestamps were stamped relative to BASE_ISO; `reanchorHistoryTimestamps`
 * shifts every row's `ts` so the newest save lands a few minutes before "now"
 * and the genesis lands ~2 days back, giving the sidebar a Today / Yesterday /
 * dated grouping regardless of the capture date. `ts` is never hashed
 * (`post_hash` covers canonical STATE only), so re-stamping keeps rows valid.
 *
 * Strictly a screenshot-fixture asset: imported only by wiki-capture-mock.ts,
 * which is itself never reachable from production (the wikiCapture flag is hard-
 * gated to dev / localhost).
 */

/** The note whose history is seeded. Matches users/alex/notes/5.json. */
export const VC_SEED_NOTE_OWNER = "alex";
export const VC_SEED_NOTE_ID = 5;

/** On-disk history path the engine reads for note 5. */
export const VC_SEED_HISTORY_PATH = `users/${VC_SEED_NOTE_OWNER}/_history/notes/${VC_SEED_NOTE_ID}.jsonl`;

/** The BASE the generator stamped timestamps against (the newest real row sits
 *  at BASE - 3 min). Re-anchoring shifts the whole timeline by (now - BASE). */
const BASE_ISO = "2026-06-01T12:00:00.000Z";

/** Real-engine-produced jsonl, base64-encoded so the embedded \n escapes inside
 *  the JSON strings survive verbatim (a template literal would eat them). */
const VC_SEED_HISTORY_JSONL_B64 =
  "";

/** Decode the embedded jsonl. Browser (atob) + node (Buffer) safe. */
function decodeSeedJsonl(): string {
  if (typeof atob === "function") {
    // atob yields a binary string; decode as UTF-8 so the °/— glyphs survive.
    const bin = atob(VC_SEED_HISTORY_JSONL_B64);
    const bytes = Uint8Array.from(bin, (c) => c.charCodeAt(0));
    return new TextDecoder("utf-8").decode(bytes);
  }
  // Node fallback (not used in the browser fixture path, kept for tests).
  return Buffer.from(VC_SEED_HISTORY_JSONL_B64, "base64").toString("utf8");
}

/**
 * Shift every row's `ts` by (now - BASE) so the newest save is ~3 min ago and
 * the timeline spans the last ~2 days. Only the `ts` field is rewritten; the
 * delta + post_hash (which encode STATE, not time) are untouched, so the rows
 * stay engine-valid. Returns the re-anchored jsonl string.
 */
export function reanchorHistoryTimestamps(jsonl: string, now: Date): string {
  const shiftMs = now.getTime() - Date.parse(BASE_ISO);
  return jsonl
    .split("\n")
    .filter((l) => l.trim().length > 0)
    .map((line) => {
      const row = JSON.parse(line) as { ts?: string };
      if (typeof row.ts === "string") {
        row.ts = new Date(Date.parse(row.ts) + shiftMs).toISOString();
      }
      return JSON.stringify(row);
    })
    .join("\n") + "\n";
}

/** The re-anchored jsonl for note 5, ready to drop into the fixture text store. */
export function buildSeedHistoryJsonl(now: Date = new Date()): string {
  return reanchorHistoryTimestamps(decodeSeedJsonl(), now);
}

/**
 * A fresh 24h `revert_undo_window` for note 5, matching the seeded history's
 * tail: the restore (row 7) moved the note off version 6 onto version 4, and
 * the undo (row 8) brought it back, so the live window points from_version 6 ->
 * to_version 4 with `reverted_by: "alex"`. `reverted_at` is set a few minutes
 * ago and `expires_at` 24h out, so `undoWindowActive` is true at capture time
 * and the "Undo restore" header button renders.
 */
export function buildSeedUndoWindow(now: Date = new Date()): {
  from_version: number;
  to_version: number;
  reverted_at: string;
  expires_at: string;
  reverted_by: string;
} {
  const revertedAt = new Date(now.getTime() - 8 * 60_000); // 8 min ago
  const expiresAt = new Date(revertedAt.getTime() + 24 * 60 * 60_000);
  return {
    from_version: 6,
    to_version: 4,
    reverted_at: revertedAt.toISOString(),
    expires_at: expiresAt.toISOString(),
    reverted_by: "alex",
  };
}
